  5→
  6→const EPSILON = 1e-8;
  7→
  8→const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
  9→
 10→const toFiniteNumber = (value) => {
 11→    const n = typeof value === 'number' ? value : Number(value);
 12→    return Number.isFinite(n) ? n : null;
 13→};
 14→
 15→const normalizeMaxEdges = (value, fallback) => {
 16→    const n = Math.floor(Number(value));
 17→    return Number.isFinite(n) && n > 0 ? n : fallback;
 18→};
 19→
 20→export const toEmbeddingArray = (value) => {
 21→    if (value == null) return null;
 22→
 23→    let source = null;
 24→
 25→    if (Array.isArray(value)) {
 26→        source = value;
 27→    } else if (ArrayBuffer.isView(value)) {
 28→        source = Array.from(value);
 29→    } else if (typeof value === 'string') {
 30→        const trimmed = value.trim();
 31→        if (!trimmed) return null;
 32→
 33→        if (trimmed.startsWith('[')) {
 34→            try {
 35→                const parsed = JSON.parse(trimmed);
 36→                if (Array.isArray(parsed)) source = parsed;
 37→            } catch {
 38→                source = null;
 39→            }
 40→        }
 41→
 42→        if (!source) {
 43→            source = trimmed
 44→                .replace(/[[\]()]/g, '')
 45→                .split(',')
 46→                .map((part) => part.trim())
 47→                .filter(Boolean);
 48→        }
 49→    }
 50→
 51→    if (!source || source.length === 0) return null;
 52→
 53→    const numeric = new Array(source.length);
 54→    for (let i = 0; i < source.length; i++) {
 55→        const n = Number(source[i]);
 56→        if (!Number.isFinite(n)) return null;
 57→        numeric[i] = n;
 58→    }
 59→    return numeric;
 60→};
 61→
 62→export const normalizeEmbedding = (vector) => {
 63→    const arr = toEmbeddingArray(vector);
 64→    if (!arr || arr.length === 0) return null;
 65→
 66→    let normSq = 0;
 67→    for (let i = 0; i < arr.length; i++) {
 68→        normSq += arr[i] * arr[i];
 69→    }
 70→    if (normSq <= EPSILON) return null;
 71→
 72→    const invNorm = 1 / Math.sqrt(normSq);
 73→    const out = new Float32Array(arr.length);
 74→    for (let i = 0; i < arr.length; i++) {
 75→        out[i] = arr[i] * invNorm;
 76→    }
 77→    return out;
 78→};
 79→
 80→export const cosineSimilarity = (a, b) => {
 81→    const arrA = toEmbeddingArray(a);
 82→    const arrB = toEmbeddingArray(b);
 83→    if (!arrA || !arrB || arrA.length === 0 || arrA.length !== arrB.length) {
 84→        return 0;
 85→    }
 86→
 87→    let dot = 0;
 88→    let normA = 0;
 89→    let normB = 0;
 90→
 91→    for (let i = 0; i < arrA.length; i++) {
 92→        const va = arrA[i];
 93→        const vb = arrB[i];
 94→        if (!Number.isFinite(va) || !Number.isFinite(vb)) return 0;
 95→        dot += va * vb;
 96→        normA += va * va;
 97→        normB += vb * vb;
 98→    }
 99→
100→    if (normA <= EPSILON || normB <= EPSILON) return 0;
101→
102→    const sim = dot / Math.sqrt(normA * normB);
103→    if (!Number.isFinite(sim)) return 0;
104→    return clamp(sim, -1, 1);
105→};
106→
107→export const computeGalaxyCentroids = (posts = []) => {
108→    const sumByUser = new Map();
109→    const postCountByUser = new Map();
110→
111→    for (const post of posts) {
112→        const userId = post?.users?.id ?? post?.user_id;
113→        if (!userId) continue;
114→
115→        const embedding = toEmbeddingArray(post?.embeddings);
116→        if (!embedding) continue;
117→
118→        if (!sumByUser.has(userId)) {
119→            sumByUser.set(userId, new Float64Array(embedding.length));
120→            postCountByUser.set(userId, 0);
121→        }
122→
123→        const sum = sumByUser.get(userId);
124→        if (!sum || sum.length !== embedding.length) continue;
125→
126→        for (let i = 0; i < embedding.length; i++) {
127→            sum[i] += embedding[i];
128→        }
129→        postCountByUser.set(userId, (postCountByUser.get(userId) || 0) + 1);
130→    }
131→
132→    const centroidByUser = new Map();
133→    for (const [userId, sum] of sumByUser.entries()) {
134→        const count = postCountByUser.get(userId) || 0;
135→        if (count <= 0) continue;
136→
137→        const mean = new Array(sum.length);
138→        for (let i = 0; i < sum.length; i++) {
139→            mean[i] = sum[i] / count;
140→        }
141→
142→        const normalized = normalizeEmbedding(mean);
143→        if (normalized) centroidByUser.set(userId, normalized);
144→    }
145→
146→    return { centroidByUser, postCountByUser };
147→};
