 87→                perfectDrawEnabled={false}
 88→                listening={false}
 89→            />
 90→            {/* Bright core */}
 91→            <Circle
 92→                radius={r * 0.5}
 93→                fill="#ffffffee"
 94→                shadowColor="#ffffff"
 95→                shadowBlur={4}
 96→                shadowOpacity={1}
 97→                perfectDrawEnabled={false}
 98→                hitStrokeWidth={r + 12}
 99→                onClick={onClick}
100→                onTap={onClick}
101→                onMouseDown={onPointerDown ? (e) => {
