Add a new factory function:

```js
/**
 * Compute initial tangential velocity for orbital motion.
 *
 * @param {{ x: number, y: number }} starPos
 * @param {{ x: number, y: number }} galaxyCenterPos
 * @param {number} galaxyCenterMass
 * @param {number} G
 * @param {number} scale - fraction of circular orbit speed (0.6 for mildly elliptical)
 * @returns {{ vx: number, vy: number }}
 */
export function computeOrbitalVelocity(starPos, galaxyCenterPos, galaxyCenterMass, G, scale = 0.6) {
    const dx = starPos.x - galaxyCenterPos.x;
    const dy = starPos.y - galaxyCenterPos.y;
    const r = Math.sqrt(dx * dx + dy * dy) || 1;

    // Circular orbit speed: v = sqrt(G * M / r)
    const vCircular = Math.sqrt(G * galaxyCenterMass / r);

    // Tangential direction (perpendicular to radial, counterclockwise)
    const tx = -dy / r;
    const ty = dx / r;

    return {
        vx: tx * vCircular * scale,
        vy: ty * vCircular * scale,
    };
}
```

