### Step 4: Refactor `useStarPhysics.js` -- Integrate Barnes-Hut into the RAF Loop

This is the largest change. The RAF loop in `useStarPhysics.js` (lines 244-336) needs to be restructured.

**New refs to add:**

```js
const positionsBufferRef = useRef(null);    // Float32Array, reused
const massesBufferRef = useRef(null);       // Float32Array, reused
const forcesBufferRef = useRef(null);       // Float32Array, reused
const bodyIndexMapRef = useRef(new Map());  // postId → index in the arrays
const indexPostIdRef = useRef([]);          // index → postId (inverse)
const galaxyCentersRef = useRef(new Map()); // userId → { x, y, mass }
```

**New pre-loop setup** (inside the RAF `tick` function, before the force application loop):

```js
// 1. Build flat arrays for Barnes-Hut from active (non-static, non-sleeping) bodies
const activeBodies = [];
const bodyIndexMap = new Map();
const indexPostId = [];

for (const [postId, body] of bodies.entries()) {
    if (body.isStatic || body.isSleeping) continue;
    if (dragBodyRef.current === body) continue;
    const idx = activeBodies.length;
    activeBodies.push(body);
    bodyIndexMap.set(postId, idx);
    indexPostId.push(postId);
}

const n = activeBodies.length;

// 2. Include galaxy centers as additional "virtual" bodies in the tree
// Galaxy centers are NOT Matter.js bodies; they are extra entries in the positions/masses arrays
const galaxyCenters = [];
const galPosMap = galaxyPositionsRef.current;
if (galPosMap && galPosMap.size > 0) {
    // Compute galaxy center mass = multiplier * sum of star masses in that galaxy
    const massByGalaxy = new Map();
    for (const [postId, body] of bodies.entries()) {
        if (body.isStatic || body.isSleeping) continue;
        const post = postsMapRef.current.get(postId);
        const uid = post?.users?.id ?? post?.user_id;
        if (!uid) continue;
        massByGalaxy.set(uid, (massByGalaxy.get(uid) || 0) + body.mass);
    }

    for (const [userId, galPos] of galPosMap.entries()) {
        const starMassSum = massByGalaxy.get(userId) || 5; // fallback
        galaxyCenters.push({
            userId,
            x: galPos.x,
            y: galPos.y,
            mass: starMassSum * PHYSICS_CONFIG.galaxyCenterMassMultiplier,
        });
    }
}

const totalN = n + galaxyCenters.length;

// 3. Fill Float32Arrays (reuse buffers if possible)
let positions = positionsBufferRef.current;
let masses = massesBufferRef.current;
if (!positions || positions.length < totalN * 2) {
    positions = new Float32Array(totalN * 2);
    positionsBufferRef.current = positions;
}
if (!masses || masses.length < totalN) {
    masses = new Float32Array(totalN);
    massesBufferRef.current = masses;
}

for (let i = 0; i < n; i++) {
    positions[i * 2] = activeBodies[i].position.x;
    positions[i * 2 + 1] = activeBodies[i].position.y;
    masses[i] = activeBodies[i].mass;
}

for (let j = 0; j < galaxyCenters.length; j++) {
    const idx = n + j;
    positions[idx * 2] = galaxyCenters[j].x;
    positions[idx * 2 + 1] = galaxyCenters[j].y;
    masses[idx] = galaxyCenters[j].mass;
}

// 4. Build quadtree
const root = buildQuadTree(positions, masses, totalN);

// 5. Build similarity lookup for semantic G-scaling
const { pairMap } = semanticMapsRef.current;
const getSimilarity = (idxA, idxB) => {
    // Only for star-star pairs (not galaxy centers)
    if (idxA >= n || idxB >= n) return null;
    const postA = indexPostId[idxA];
    const postB = indexPostId[idxB];
    const pairs = pairMap.get(postA);
    if (!pairs) return null;
    for (const p of pairs) {
        if (p.otherPostId === postB) return p.similarity;
    }
    return null;
};

// 6. Compute forces
for (let i = 0; i < n; i++) {
    const force = computeBodyForceWithSimilarity(
        root, i, positions, masses,
        PHYSICS_CONFIG.gravityG,
        PHYSICS_CONFIG.gravityTheta,
        PHYSICS_CONFIG.gravitySoftening,
        getSimilarity
    );

    const body = activeBodies[i];
    Body.applyForce(body, body.position, {
        x: force.fx,
        y: force.fy,
    });

    // 7. Residual anchor spring (weak, only significant at large displacements)
    const postId = indexPostId[i];
    const anchor = anchors.get(postId);
    if (anchor) {
        const dx = anchor.x - body.position.x;
        const dy = anchor.y - body.position.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        // Only apply if gravity from galaxy center is not dominant
        if (dist > 500) {
            Body.applyForce(body, body.position, {
                x: dx * PHYSICS_CONFIG.residualAnchorK * body.mass,
                y: dy * PHYSICS_CONFIG.residualAnchorK * body.mass,
            });
        }
    }
}
```

